"use strict";(self.webpackChunkwoocommerce_ebay_connector=self.webpackChunkwoocommerce_ebay_connector||[]).push([[297],{4278(e,t,a){a.r(t),a.d(t,{comp:()=>n,data:()=>d});var o=a(641);const r=a.p+"assets/img/categories-for-import.242062dc.webp",s=a.p+"assets/img/refresh-produtcs.0da798fe.webp",i={},n=(0,a(6262).A)(i,[["render",function(e,t){return(0,o.uX)(),(0,o.CE)("div",null,[...t[0]||(t[0]=[(0,o.Fv)('<h1 id="product-listing-–-woocommerce-ebay-connector" tabindex="-1"><a class="header-anchor" href="#product-listing-–-woocommerce-ebay-connector"><span>Product Listing – WooCommerce eBay Connector</span></a></h1><p>This guide explains how to import products from eBay to WooCommerce.</p><hr><h2 id="import-products-from-ebay" tabindex="-1"><a class="header-anchor" href="#import-products-from-ebay"><span>Import Products from eBay</span></a></h2><p>The admin can import products from eBay to the WooCommerce store.</p><p>Navigate to <strong>WC eBay Connector → Manage Products</strong> to see the import options:</p><ul><li><strong>Import Products From eBay</strong> – Import all active eBay products</li><li><strong>Import Products Date-wise</strong> – Import multiple products according to specific dates</li></ul><h3 id="steps-to-import" tabindex="-1"><a class="header-anchor" href="#steps-to-import"><span>Steps to Import</span></a></h3><ol><li>Click <strong>Import Products from eBay</strong> to start the import.</li><li>This will create temporary product data and store it in the WooCommerce store.</li><li>A background process for image import also runs during product import.</li><li>You can start and stop the product image import process as required.</li></ol><blockquote><p><strong>Note:</strong> Only products that are currently listed as <strong>active</strong> on eBay will be imported.</p></blockquote><h3 id="category-assignment-during-import" tabindex="-1"><a class="header-anchor" href="#category-assignment-during-import"><span>Category Assignment During Import</span></a></h3><ul><li>If category mapping is <strong>not done</strong> for the eBay product category, imported products will be assigned to the <strong>Default Category</strong> as per configuration.</li><li>If category mapping <strong>is done</strong>, imported products will be assigned to the mapped category.</li><li>If <strong>Auto Mapping is enabled</strong>, products imported from eBay will be assigned to the eBay category already imported in WooCommerce. <a class="doc-image-link" href="./assets/categories-for-import.webp"><img src="'+r+'" alt="screenshots"></a></li></ul><hr><h2 id="refresh-products" tabindex="-1"><a class="header-anchor" href="#refresh-products"><span>Refresh Products</span></a></h2><p>The <strong>Refresh Product</strong> button lets you update your product information from eBay automatically.</p><p>When you click the button, a popup will appear notifying you that this is a time-consuming process. It advises you to use the <strong>Refresh eBay Products</strong> option only if:</p><ul><li>Real-time sync is off, or</li><li>Products are out of sync</li></ul><p>Once you click <strong>Yes</strong>, your product listings will be updated with the latest details from eBay.</p><p><a class="doc-image-link" href="./assets/refresh-produtcs.webp"><img src="'+s+'" alt="refesh-products"></a></p><hr><h2 id="supported-product-types" tabindex="-1"><a class="header-anchor" href="#supported-product-types"><span>Supported Product Types</span></a></h2><table><thead><tr><th>Product Type</th><th>Import</th><th>Export</th></tr></thead><tbody><tr><td>Simple Products</td><td>✅</td><td>✅</td></tr><tr><td>Variable Products</td><td>✅</td><td>✅</td></tr><tr><td>Auction-type Products</td><td>✅ (imported as Simple)</td><td>❌</td></tr></tbody></table><hr><h2 id="synced-product-data" tabindex="-1"><a class="header-anchor" href="#synced-product-data"><span>Synced Product Data</span></a></h2><p>The following product data is synced between WooCommerce and eBay:</p><ul><li>SKU</li><li>Product Name / Title</li><li>Description</li><li>Stock / Inventory</li><li>Images</li><li>Categories</li><li>Price</li><li>eBay Conditions &amp; Specifications</li><li>Attributes</li></ul><hr>',27)])])}]]),d=JSON.parse('{"path":"/documentation/product-listing.html","title":"Product Listing – WooCommerce eBay Connector","lang":"en-US","frontmatter":{"prev":"/documentation/category-mapping.html","next":"/documentation/export-product.html"},"git":{"updatedTime":1774967427000,"contributors":[{"name":"shakir.hussain","username":"","email":"shakir.hussain421@webkul.in","commits":1},{"name":"aadesh","username":"","email":"aadesh.8209@webkul.in","commits":3},{"name":"nikhilsharma.qa322","username":"","email":"nikhilsharma.qa322@webkul.in","commits":2}],"changelog":[{"hash":"b0ac37d62fd38e5863a485e67c0707465c06a10a","time":1774967427000,"email":"nikhilsharma.qa322@webkul.in","author":"nikhilsharma.qa322","message":"update the content, images and add the zoom functionality and lightbox image"},{"hash":"ba6d2edb5098181920dea430c0c44bcb4f5e451b","time":1774878680000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"update images"},{"hash":"8ce519dabc56b69d55470338a513bcdf5f2dcd07","time":1772807380000,"email":"nikhilsharma.qa322@webkul.in","author":"nikhilsharma.qa322","message":"fix the image issue"},{"hash":"2d5c39163a248635a79c60d8508c0716b0a11c03","time":1772114569000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"add export product"},{"hash":"a3379ad1acde7722f52940c853addb733657393e","time":1771942912000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"update images"},{"hash":"277c5a1bdc13e06551e102ee26c728b6b048e50b","time":1771481506000,"email":"shakir.hussain421@webkul.in","author":"shakir.hussain","message":"updated ebay blog and move to dev"}]},"filePathRelative":"documentation/product-listing.md"}')}}]);